INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 401, 0.0, 2, "アヤネ", 24001, "2020/07/31 12:00:00", 102301, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 402, 0.0, 1, "アヤネ", 24002, "2020/07/31 12:00:00", 102301, 10046, 2.21, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 403, 0.0, 2, "アヤネ", 24003, "2020/07/31 12:00:00", 102301, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 701, 0.0, 2, "アサヒ", 24004, "2020/07/31 12:00:00", 192201, 10046, 1.99, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 702, 0.0, 1, "アサヒ", 24005, "2020/07/31 12:00:00", 192201, 10046, 2.21, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 703, 0.0, 2, "アサヒ", 24006, "2020/07/31 12:00:00", 192201, 10046, 3.33, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 801, 0.0, 2, "部員３", 24007, "2020/07/31 12:00:00", 192301, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 802, 0.0, 1, "部員３", 24008, "2020/07/31 12:00:00", 192301, 10046, 2.68, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 803, 0.0, 2, "部員３", 24009, "2020/07/31 12:00:00", 192301, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("やった！", 501, 0.0, 1, "", 24010, "2020/07/31 12:00:00", 192501, 10046, 0.0, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("勝ったよ！", 502, 0.0, 1, "", 24011, "2020/07/31 12:00:00", 192501, 10046, 0.0, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい調子！", 503, 0.0, 1, "", 24012, "2020/07/31 12:00:00", 192501, 10046, 0.0, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 111, 0.0, 6, "ミサト", 24013, "2020/07/31 12:00:00", 113501, 10046, 5.33, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 112, 0.0, 1, "ミサト", 24014, "2020/07/31 12:00:00", 113501, 10046, 6.85, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113, 0.0, 1, "ミサト", 24015, "2020/07/31 12:00:00", 113501, 10046, 3.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 611, 0.0, 1, "ダイチ", 24016, "2020/07/31 12:00:00", 192401, 10046, 6.11, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 612, 0.0, 1, "ダイチ", 24017, "2020/07/31 12:00:00", 192401, 10046, 6.75, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 613, 0.0, 2, "ダイチ", 24018, "2020/07/31 12:00:00", 192401, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 211, 0.0, 2, "ハツネ", 24019, "2020/07/31 12:00:00", 113401, 10046, 4.52, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 212, 0.0, 2, "ハツネ", 24020, "2020/07/31 12:00:00", 113401, 10046, 3.89, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 213, 0.0, 1, "ハツネ", 24021, "2020/07/31 12:00:00", 113401, 10046, 13.49, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 311, 0.0, 1, "カヤ", 24022, "2020/07/31 12:00:00", 106501, 10046, 3.17, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 312, 0.0, 1, "カヤ", 24023, "2020/07/31 12:00:00", 106501, 10046, 4.42, "2030/12/17 14:59:59", 24, 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 313, 0.0, 6, "カヤ", 24024, "2020/07/31 12:00:00", 106501, 10046, 2.89, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 421, 0.0, 4, "アヤネ", 24025, "2020/07/31 12:00:00", 102301, 10046, 3.71, "2030/12/17 14:59:59", 24, 3, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 721, 0.0, 2, "アサヒ", 24026, "2020/07/31 12:00:00", 192201, 10046, 5.1, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 821, 0.0, 1, "部員３", 24027, "2020/07/31 12:00:00", 192301, 10046, 4.34, "2030/12/17 14:59:59", 24, 3, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい勝負だったよ\nまたやろうね", 521, 0.0, 1, "", 24028, "2020/07/31 12:00:00", 192501, 10046, 0.0, "2030/12/17 14:59:59", 24, 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 101, 0.0, 1, "ミサト", 24029, "2020/07/31 12:00:00", 113501, 10046, 5.62, "2030/12/17 14:59:59", 24, 2, -360.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 102, 0.0, 1, "ミサト", 24030, "2020/07/31 12:00:00", 113501, 10046, 9.58, "2030/12/17 14:59:59", 24, 2, -360.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 103, 0.0, 2, "ミサト", 24031, "2020/07/31 12:00:00", 113501, 10046, 0.0, "2030/12/17 14:59:59", 24, 2, -360.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 104, 0.0, 2, "ミサト", 24032, "2020/07/31 12:00:00", 113501, 10046, 9.13, "2030/12/17 14:59:59", 24, 1, -360.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 105, 0.0, 1, "ミサト", 24033, "2020/07/31 12:00:00", 113501, 10046, 8.27, "2030/12/17 14:59:59", 24, 2, -360.0);
